TOKEN = 'oauth:your_bot_token_here'  # This is the bot token linked to the bot account (Example account: tankz135)
BROADCASTER_TOKEN = 'oauth:your_broadcaster_token_here'  # This is the bot token linked to the streaming account (Example account: cobydoesstuff)
REFRESH_TOKEN = 'your_refresh_token_here' # Optional, only needed if you want to implement token refreshing (I honestly just use it for storage)
NICK = 'your_bot_username_here' # The username of the bot account (Example name: tankz135)
CLIENT_ID = 'your_client_id_here'  # The Client ID from your Twitch Developer application
BOT_USER_ID = 'your_bot_user_id_here'  # User ID for the bot account (Example: 1427622787, You can get this from https://www.streamweasels.com/tools/convert-twitch-username-%20to-user-id/)
CLIENT_SECRET = 'your_client_secret_here'  # Optional, only if you need it
OBS_WEBSOCKET_PASSWORD = 'your_obs_websocket_password_here'  # Optional, only if you set a password in OBS

# Remove the Example: from the filename and fill in the above fields with the appropriate values for your Twitch bot and OBS setup.